import { Hono } from 'hono'
import { cors } from 'hono/cors'
import { renderer } from './renderer'

type Track = { title: string; url: string }
type Playlist = { name: string; tracks: Track[] }
type PlaylistData = { playlists: Playlist[] }

// CloudflareBindings is auto-generated by `wrangler types`.
// PLAYLIST_AUTH_TOKEN is a Workers Secret — set via `wrangler secret put`.
type AppBindings = CloudflareBindings & { PLAYLIST_AUTH_TOKEN?: string }

const app = new Hono<{ Bindings: AppBindings }>()

app.use(renderer)
app.use('/playlists', cors({ origin: '*', allowMethods: ['GET', 'PUT', 'OPTIONS'] }))

app.get('/', (c) => {
  return c.render(<h1>Hello!</h1>)
})

app.get('/status', (c) => {
  return c.json({
    message: 'Hello VRChat',
    updatedAt: new Date().toISOString(),
  })
})

app.get('/playlists', async (c) => {
  const data = await c.env.PLAYLIST_STORE.get<PlaylistData>('playlists', 'json')
  return c.json(data ?? { playlists: [] })
})

app.put('/playlists', async (c) => {
  const secret = c.env.PLAYLIST_AUTH_TOKEN
  const auth = c.req.header('Authorization')
  if (!secret || auth !== `Bearer ${secret}`) {
    return c.json({ error: 'Unauthorized' }, 401)
  }
  const body = await c.req.json<PlaylistData>()
  await c.env.PLAYLIST_STORE.put('playlists', JSON.stringify(body))
  return c.json({ ok: true })
})

export default app
